-- W1.6 questions batch 6160/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-cbdcc9ff-moex-00022', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-112-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '機關允許得標廠商將工程採購分包予其他廠商，但分包後於契約執行期
間，時有發生廠商因財務危機造成停工，並造成分包廠商無法直接向機
關請求給付價金或報酬。試論政府採購法如何解決這個問題？並說明分
包廠商直接向機關請求給付之要件。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "397269db592b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "110", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00023', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '甲身無分文，卻想利用機會不法拿取高價手錶而進入錶店，甲向店員乙
謊稱要買手錶，請乙拿出高價 A錶供其觀賞挑選。乙在取出手錶前，依
照店內守則，先悄悄鎖住店內玻璃門，以防萬一，但所有動作都已被甲
觀察到。甲查看 A 錶時，乙主動將 A 錶戴在甲手上，並逐一解說 A 錶
的功能，此時甲又指著玻璃櫃台內另一只錶，要求乙也拿出來比較，乙
不疑有他，在低頭解鎖準備拿出該錶時，甲戴著A錶跑向店門口，並以
尖銳物敲擊玻璃門，玻璃門脆裂，甲衝撞逃離錶店，乙從錶店追出，因
距離甲很近，乙伸手想拉住甲的衣服，卻因踩到地上碎玻璃滑倒，身上
多處被玻璃割傷，甲順利逃走。試問甲的行為依刑法如何論處。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "989768362d17", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00024', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '甲為 16歲乙的指定監護人，甲心儀乙一段時日，某日乙請甲同意讓其動
用自己的特有財產，購買高價首飾。甲明知該高價首飾就乙的日常生活
而言，不但不必要且不相當，卻覬覦乙的身體，謊稱只要乙願意與甲發
生性行為，甲願意同意乙的要求，雖然乙素來討厭甲，卻仍答應甲的交
換條件，甚至在第一次兩人性行為後，乙竟不顧自己不喜歡甲的事實，
積極與甲交往，希望藉由甲的資力讓自己有更好的生活享受。之後甲、
乙發生第二次性行為時，乙詢問甲一起去購買之前所說高價首飾的具體
時間，甲認兩人已為戀人，遂坦誠相告之前因為想與乙有親密關係，所
以假稱同意，並說明該首飾非乙日常生活必要，不會同意乙購買，但日
後甲會用自己的錢給乙添購高品質的生活物資。乙發覺自己被騙，非常
生氣即刻與甲分手。乙以甲的長相與身形特徵向警局報案，冒稱自己遭
到居家附近傳聞已久卻尚未落網之「蒙面狼」性侵。試問甲、乙的行為
依刑法如何論處。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "989768362d17", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00025', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '甲涉犯毒品危害防制條例罪嫌，經檢察官依法提起公訴，辯護人乙於審
判中主張證人丙在偵查中向檢察官所為之證述，並無結文附卷，顯未經
具結，自無證據能力，檢察官遂聲請證人丙至法庭作證，丙於法庭上證
稱：「其於偵查中曾簽具結文」云云，審判終結，法院以前述證據形成心
證，諭知甲有罪。辯護人不服，以「檢察官之訊問筆錄雖記載『諭知具
結之義務及偽證之處罰，並命證人朗讀結文後具結』等語，然無結文附
卷可稽，因不符法定具結程序採書面結文之形式要件，應不發生具結之
效力，其證言無證據能力。」提起上訴。試論辯護人之主張是否有理由？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "989768362d17", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00026', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-de0a21a2', 'sub-judicial-cbdcc9ff-01', NULL, 'essay', '被告甲涉犯刑法酒駕致人於死罪嫌，經檢察官依法提起公訴，審判中，
被告甲及其辯護人乙，對於證人丙於審判外之陳述，均明示同意作為證
據，復經提示上開供述證據時，亦併就證據能力表示沒有意見。法院審
酌上開證據作成時之情況，認無不適當之情形，復敘明符合證據適當性
之理由，乃依法踐行調查程序，認定被告甲有罪。甲依法提起上訴，經
上訴審撤銷原審判決，發回更審。試論被告甲及辯護人乙得否於更審第
一次審判期日時，撤回同意證人丙之傳聞證據之證據能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "989768362d17", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00027', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '黃先生回到母校，看見校長室牆上掛滿匾額，下列那一個題辭不適合出現？', '["時雨春風", "澤被三臺", "絃歌盈耳", "功著杏林"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00028', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '「愛，是人類生命存在的心靈經驗之一，只有真切地面對自己以及所愛之人內在活生 生的心靈，才能照見彼此不能相愛的障礙而加以克服。然而，他們卻遺忘了自己的 存在，只是不斷地追逐著各種外在的知識，以為這樣就能幸福快樂。」 下列敘述何者最貼近本文的旨趣？', '["知識的追逐讓人們忘了如何相愛", "體認自身之存在為追逐知識之本", "人經常忘記照見自己而產生了相愛的障礙", "相愛的根本在於面對彼此的內心而非知識"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00029', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '「美是一種生命整體存在感的湧現。當此際必然是物我兩忘，情景交融，渾成一片， 而容不下絲毫的分辨與思維。當天邊飛過一抹彩霞，你只合目瞪口呆；連一句『好 美啊』的呢喃，都已是心靈對此境的意識與抽離，也早已構成對美的留戀與破壞。」 根據上文，最符合美的感受是：', '["盡在不言中", "物我保持距離", "感官與意識的交融", "生命主體的思維湧現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00030', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '「大多數的商業圖表都是披薩，餡料不多以免消化不良，它能在短時間內提供資訊， 用不著太多文字說明。客戶資料蒐集差不多了，就畫個條狀圖。計畫又訂出新的期 限，就畫個時程圖。但有些會議需要很多說明，例如剛併購一家公司，要向高層主 管解說營運策略如何調整，這時，披薩無法滿足胃口，要端出全套酒席，展示精細 的圖表。這種圖表能醞釀創意，引發大家交換意見，進而解決問題。」 下列敘述，最符合上文觀點的是：', '["披薩式圖表適用於基層會議，酒席式圖表適用於主管會議", "披薩式圖表適用於宣達要點，酒席式圖表適用於探討細節", "披薩式與酒席式圖表雖然各有功能，但皆應儘量少用文字", "披薩式與酒席式圖表雖然繁簡不一，但皆為引發充分討論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00031', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '「有一座龐大的旅館，設備陳舊，管理鬆懈，營業額一落千丈。旅館的所有人聘請一 位專家來從事革新和整頓。三個月後，專家對旅館的現況有了透徹的了解，提出一 份詳細的計畫，主張把房子拆掉重新建造大樓，現有工作人員一律遣散，重新招考 訓練。旅館所有人無法接受這樣的計畫，聘請另一位專家來擔任經理。這位專家在 視察旅館的業務之後，下令換裝所有房間的自來水龍頭。新的龍頭，式樣美觀，操 作方便，絕不漏水，旅客在半夜再也聽不到滴漏之聲，可以安享一夜好睡了。就這 樣，新任經理從小處著手，積小為大，終於使旅館的作風煥然一新。旅客們發現， 這家旅館的房子雖然陳舊，但是堅固；式樣雖然古老，但是引人。於是近者悅，遠 者來。」 根據上文，旅館終能近悅遠來，其主要關鍵在於管理者：', '["不愛虛名，惟儉是尚", "前事不忘，後事之師", "圖難於其易，為大於其細", "毀譽無動於衷，榮辱在所不計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL)
